-- ============================================================
-- BAGIAN 0: INITIALIZATION & SETUP
-- ============================================================
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE EXTENSION IF NOT EXISTS "pgcrypto"; -- Opsional untuk enkripsi di DB

-- ============================================================
-- NOMOR 1: MASTER USERS (Login & Access Management)
-- ============================================================
CREATE TABLE master_users (
    user_id       UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    username      VARCHAR(50) UNIQUE NOT NULL,
    password_hash TEXT NOT NULL, 
    full_name     VARCHAR(100),
    role          VARCHAR(20) DEFAULT 'teknisi', -- admin, teknisi, viewer
    is_active     BOOLEAN DEFAULT TRUE,
    created_at    TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

-- ============================================================
-- NOMOR 2: MIKROTIK BOARDS (CORE ASSET)
-- ============================================================
CREATE TABLE mikrotik_boards (
    board_id          UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    
    -- Identitas & Manajemen
    board_name        VARCHAR(100) NOT NULL,
    mikrotik_identity VARCHAR(100),
    board_model       VARCHAR(50),
    site_group        VARCHAR(50) DEFAULT 'Umum',
    
    -- Jaringan & Port
    mac_address       MACADDR NOT NULL,
    ip_address        INET NOT NULL,
    port_ssh          INT DEFAULT 22,
    port_api          INT DEFAULT 8728,
    port_winbox       INT DEFAULT 8291,
    port_ftp          INT DEFAULT 21,
    
    -- Status & Flags
    is_online         BOOLEAN DEFAULT FALSE,
    is_monitor        BOOLEAN DEFAULT TRUE,
    is_public_review  BOOLEAN DEFAULT TRUE,
    is_maintenance    BOOLEAN DEFAULT FALSE,
    
    -- Metadata
    last_ping_at      TIMESTAMP WITH TIME ZONE,
    created_at        TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    updated_at        TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP 
);

CREATE INDEX idx_board_logic ON mikrotik_boards(is_online, is_monitor, is_public_review);
CREATE INDEX idx_board_site ON mikrotik_boards(site_group);

-- ============================================================
-- NOMOR 3: BOARD CREDENTIALS (Encrypted)
-- ============================================================
CREATE TABLE board_credentials (
    cred_id                     SERIAL PRIMARY KEY,
    board_id                    UUID REFERENCES mikrotik_boards(board_id) ON DELETE CASCADE,
    username_mikrotik           VARCHAR(50) NOT NULL,
    password_mikrotik_encrypted TEXT NOT NULL, -- AES-256-GCM Encrypted
    updated_at                  TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);
CREATE INDEX idx_board_credentials_board_id ON board_credentials(board_id);

-- ============================================================
-- NOMOR 4: USER BOARD ACCESS (RBAC)
-- ============================================================
CREATE TABLE user_board_access (
    access_id  SERIAL PRIMARY KEY,
    user_id    UUID REFERENCES master_users(user_id) ON DELETE CASCADE,
    board_id   UUID REFERENCES mikrotik_boards(board_id) ON DELETE CASCADE,
    granted_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT unique_access UNIQUE(user_id, board_id)
);
CREATE INDEX idx_user_board_access_user_id ON user_board_access(user_id);
CREATE INDEX idx_user_board_access_board_id ON user_board_access(board_id);

-- ============================================================
-- NOMOR 5: VPN PROFILES
-- ============================================================
CREATE TABLE vpn_profiles (
    vpn_id                 SERIAL PRIMARY KEY,
    board_id               UUID REFERENCES mikrotik_boards(board_id) ON DELETE CASCADE,
    
    vpn_type               VARCHAR(20) DEFAULT 'L2TP/IPSEC',
    vpn_api                VARCHAR(255),
    vpn_username           VARCHAR(50),
    vpn_password_encrypted TEXT,
    
    vpn_ssh                VARCHAR(255),
    vpn_ftp                VARCHAR(255),
    vpn_winbox             VARCHAR(255),
    
    is_connected           BOOLEAN DEFAULT FALSE,
    last_connected_at      TIMESTAMP WITH TIME ZONE
);
CREATE INDEX idx_vpn_profiles_board_id ON vpn_profiles(board_id);

-- ============================================================
-- NOMOR 6: BOARD CLIENT STATS (Monitoring User)
-- ============================================================
CREATE TABLE board_client_stats (
    stat_id       BIGINT NOT NULL, -- Changed from BIGSERIAL for Partitioning Best Practice
    board_id      UUID REFERENCES mikrotik_boards(board_id) ON DELETE CASCADE,
    total_hotspot INT DEFAULT 0,
    total_pppoe   INT DEFAULT 0,
    total_active  INT GENERATED ALWAYS AS (total_hotspot + total_pppoe) STORED,
    accuracy_pct  NUMERIC(5,2) DEFAULT 100.00, -- Metadata: Persentase akurasi data
    log_time      TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (stat_id, log_time)
) PARTITION BY RANGE (log_time);
CREATE INDEX idx_client_stats_time ON board_client_stats(board_id, log_time DESC);

-- ============================================================
-- NOMOR 7: BOARD RESOURCE STATS (Health Check)
-- ============================================================
CREATE TABLE board_resource_stats (
    resource_id   BIGINT NOT NULL, -- Changed from BIGSERIAL
    board_id      UUID REFERENCES mikrotik_boards(board_id) ON DELETE CASCADE,
    cpu_load      INT,             -- 0-100%
    free_memory   BIGINT,          -- Bytes
    free_hdd      BIGINT,          -- Bytes
    uptime        INTERVAL,
    accuracy_pct  NUMERIC(5,2) DEFAULT 100.00,
    log_time      TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (resource_id, log_time)
) PARTITION BY RANGE (log_time);
CREATE INDEX idx_resource_stats_time ON board_resource_stats(board_id, log_time DESC);

-- ============================================================
-- NOMOR 8: BOARD SPEED STATS (Traffic)
-- ============================================================
CREATE TABLE board_speed_stats (
    speed_id       BIGINT NOT NULL, -- Changed from BIGSERIAL
    board_id       UUID REFERENCES mikrotik_boards(board_id) ON DELETE CASCADE,
    interface_name VARCHAR(100) NOT NULL,
    download_mbps  NUMERIC(15,2) DEFAULT 0, -- Standardized to NUMERIC(15,2)
    upload_mbps    NUMERIC(15,2) DEFAULT 0, -- Standardized to NUMERIC(15,2)
    accuracy_pct   NUMERIC(5,2) DEFAULT 100.00,
    log_time       TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (speed_id, log_time)
) PARTITION BY RANGE (log_time);
CREATE INDEX idx_speed_interface_time ON board_speed_stats(board_id, interface_name, log_time DESC);

-- ============================================================
