CREATE INDEX idx_board_daily_summary_lookup ON board_daily_summary(board_id, log_date DESC);

-- ============================================================
-- NOMOR 9a: BOARD INTERFACE DAILY SUMMARY (Aggregation per Port)
-- ============================================================
CREATE TABLE board_interface_daily_summary (
    summary_id           SERIAL PRIMARY KEY,
