CREATE INDEX idx_interface_summary_lookup ON board_interface_daily_summary (board_id, interface_name, log_date DESC);

-- ============================================================
-- NOMOR 9b: BOARD MONTHLY SUMMARY (Aggregation)
-- ============================================================
CREATE TABLE board_monthly_summary (
    summary_id           SERIAL PRIMARY KEY,
    board_id             UUID REFERENCES mikrotik_boards(board_id) ON DELETE CASCADE,
    
    avg_download         NUMERIC(15,2) DEFAULT 0, -- Standardized from BIGINT
    max_download         NUMERIC(15,2) DEFAULT 0, -- Standardized from BIGINT
    total_download_bytes BIGINT DEFAULT 0,
    
    avg_upload           NUMERIC(15,2) DEFAULT 0, -- Standardized from BIGINT
    max_upload           NUMERIC(15,2) DEFAULT 0, -- Standardized from BIGINT
    total_upload_bytes   BIGINT DEFAULT 0,
    
    avg_cpu_load         INT DEFAULT 0,
    max_cpu_load         INT DEFAULT 0,
    
    avg_hotspot_users    INT DEFAULT 0,
