CREATE INDEX idx_board_monthly_summary_lookup ON board_monthly_summary(board_id, log_month DESC);

-- ============================================================
-- NOMOR 10: BOARD EVENTS (Audit Trail)
-- ============================================================
CREATE TABLE board_events (
    event_id       BIGINT NOT NULL, -- Changed from BIGSERIAL
    board_id       UUID REFERENCES mikrotik_boards(board_id) ON DELETE CASCADE,
    event_category VARCHAR(20), -- connection, system, auth
    event_level    VARCHAR(10), -- info, warning, critical
    event_name     TEXT NOT NULL,
    event_detail   TEXT,
    performed_by   UUID REFERENCES master_users(user_id) ON DELETE SET NULL,
    is_reset_event BOOLEAN DEFAULT FALSE,
    accuracy_pct   NUMERIC(5,2) DEFAULT 100.00,
    log_time       TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (event_id, log_time)
) PARTITION BY RANGE (log_time);
CREATE INDEX idx_board_events_board_time ON board_events(board_id, log_time DESC);

-- Trigger Otomatisasi Log Status
CREATE OR REPLACE FUNCTION fungsi_auto_log_status()
RETURNS TRIGGER AS $$
BEGIN
    IF (OLD.is_online != NEW.is_online) THEN
        INSERT INTO board_events (event_id, board_id, event_category, event_level, event_name, event_detail)
        VALUES (
            nextval('board_events_event_id_seq'), -- Explicitly handle sequence for partitioning
            NEW.board_id, 
            'connection', 
            CASE WHEN NEW.is_online THEN 'info' ELSE 'critical' END,
            CASE WHEN NEW.is_online THEN 'Router Connectivity Changed' ELSE 'Router Offline' END,
            CASE WHEN NEW.is_online THEN 'Router is now Online' ELSE 'Router Ping Timeout' END
        );
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_pencatat_status
AFTER UPDATE OF is_online ON mikrotik_boards
FOR EACH ROW EXECUTE PROCEDURE fungsi_auto_log_status();

