-- ============================================================
-- PHASE 8: AUTOMATION (Mass Config & ZTP)
-- ============================================================
CREATE TABLE automation_jobs (
    job_id       UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    job_type     VARCHAR(50) NOT NULL, -- mass_config, reboot
    payload      JSONB,
    description  TEXT,
    status       VARCHAR(20) DEFAULT 'pending', -- pending, running, completed
    created_by   UUID REFERENCES master_users(user_id),
    created_at   TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    completed_at TIMESTAMP WITH TIME ZONE
);
CREATE INDEX idx_automation_jobs_created_by ON automation_jobs(created_by);

CREATE TABLE automation_logs (
    log_id        BIGSERIAL PRIMARY KEY,
    job_id        UUID REFERENCES automation_jobs(job_id) ON DELETE CASCADE,
    board_id      UUID REFERENCES mikrotik_boards(board_id) ON DELETE CASCADE,
    status        VARCHAR(20) DEFAULT 'pending', -- pending, success, failed
    output        TEXT,
    error_message TEXT,
    executed_at   TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);
CREATE INDEX idx_automation_logs_job_id ON automation_logs(job_id);
CREATE INDEX idx_automation_logs_board_id ON automation_logs(board_id);

CREATE TABLE ztp_queue (
    ztp_id         UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    mac_address    MACADDR NOT NULL,
    ip_address     INET NOT NULL,
    identity       VARCHAR(100),
    model          VARCHAR(50),
    router_version VARCHAR(50),
    temp_username  VARCHAR(50),
    temp_password  TEXT,
    status         VARCHAR(20) DEFAULT 'pending', -- pending, approved, rejected
    requested_at   TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    processed_at   TIMESTAMP WITH TIME ZONE,
    processed_by   UUID REFERENCES master_users(user_id)
);
CREATE INDEX idx_ztp_status ON ztp_queue(status);
CREATE INDEX idx_ztp_mac_address ON ztp_queue(mac_address);

-- ============================================================
-- PHASE 14: AUDIT LOGS (Security & Compliance)
-- ============================================================
CREATE TABLE audit_logs (
    log_id          SERIAL PRIMARY KEY,
    user_id         UUID REFERENCES master_users(user_id) ON DELETE SET NULL,
    action          VARCHAR(50) NOT NULL, -- LOGIN, CREATE, UPDATE, DELETE
    target_resource VARCHAR(100) NOT NULL,
    details         JSONB,
    ip_address      VARCHAR(45),
    status          VARCHAR(20) DEFAULT 'SUCCESS',
    created_at      TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);
CREATE INDEX idx_audit_logs_user_id ON audit_logs(user_id);
CREATE INDEX idx_audit_logs_action ON audit_logs(action);
CREATE INDEX idx_audit_logs_details_gin ON audit_logs USING GIN (details); -- Optimized GIN Index
